           // scripted_lookups\n\n}\n\n\nfunction XmlWinEventLog($source: dataset):dataset {\n    return | from $source\n           // auto kv mode\n\n\n           // regex based extractions\n\n           | rex field=_raw /(?ms)<System(?:\\s+[^>]+)?>(?P<System_Props_Xml>.*?)<\\/System>/\n           | rex field=_raw /(?ms)<EventData(?:\\s+[^>]+)?>(?P<EventData_Xml>.*?)<\\/EventData>/\n           | rex field=_raw /(?ms)<UserData(?:\\s+[^>]+)?>(?P<UserData_Xml>.*?)<\\/UserData>/\n           | rex field=_raw /(?ms)<DebugData(?:\\s+[^>]+)?>(?P<DebugData_Xml>.*?)<\\/DebugData>/\n           | rex field=_raw /(?ms)<RenderingInfo(?:\\s+[^>]+)?>(?P<RenderingInfo_Xml>.*?)<\\/RenderingInfo>/\n           | eval tmp_System_Props_Xml = replace(System_Props_Xml, /(?ms)<(\\w*)>([^<]*)<\\/\\1>/, "##SEP##\\\\1##VAL_SEP##\\\\2##SEP##")\n| eval tmp_System_Props_Xml = filter(split(tmp_System_Props_Xml, "##SEP##"), $row -> match($row, /.*##VAL_SEP##.*/ ))\n| eval tmp_System_Props_Xml = map(tmp_System_Props_Xml, $row -> split($row, "##VAL_SEP##" ))\n| eval tmp_System_Props_Xml = reduce(tmp_System_Props_Xml, json_object(), ($acc, $row)-> if(isnull(json_extract($acc, replace(trim($row[0]), /\\s/, "_"))),json_set($acc, replace(trim($row[0]), /\\s/, "_"), $row[1]),json_set($acc, replace(trim($row[0]), /\\s/, "_"), json_array(json_extract($acc, replace(trim($row[0]), /\\s/,"_")), $row[1]))))\n| flatten tmp_System_Props_Xml\n| fields - tmp_System_Props_Xml\n           | eval tmp_System_Props_Xml = replace(System_Props_Xml, /(?ms)\\s([^\\s=]+)\\s*=\\s*(\\\'[^<\\\']*\\\'|"[^<"]*")/, "##SEP##\\\\1##VAL_SEP##\\\\2##SEP##")\n| eval tmp_System_Props_Xml = filter(split(tmp_System_Props_Xml, "##SEP##"), $row -> match($row, /.*##VAL_SEP##.*/ ))\n| eval tmp_System_Props_Xml = map(tmp_System_Props_Xml, $row -> split($row, "##VAL_SEP##" ))\n| eval tmp_System_Props_Xml = reduce(tmp_System_Props_Xml, json_object(), ($acc, $row)-> if(isnull(json_extract($acc, replace(trim($row[0]), /\\s/, "_"))),json_set($acc, replace(trim($row[0]), /\\s/, "_"), $row[1]),json_set($acc, replace(trim($row[0]), /\\s/, "_"), json_array(json_extract($acc, replace(trim($row[0]), /\\s/,"_")), $row[1]))))\n| flatten tmp_System_Props_Xml\n| fields - tmp_System_Props_Xml\n           | eval tmp_EventData_Xml = replace(EventData_Xml, /<(?:\\w+)\\sName=\'([^>]*)\'\\/?>([^<]*)(?:<\\/\\1>)?/, "##SEP##\\\\1##VAL_SEP##\\\\2##SEP##")\n| eval tmp_EventData_Xml = filter(split(tmp_EventData_Xml, "##SEP##"), $row -> match($row, /.*##VAL_SEP##.*/ ))\n| eval tmp_EventData_Xml = map(tmp_EventData_Xml, $row -> split($row, "##VAL_SEP##" ))\n| eval tmp_EventData_Xml = reduce(tmp_EventData_Xml, json_object(), ($acc, $row)-> if(isnull(json_extract($acc, replace(trim($row[0]), /\\s/, "_"))),json_set($acc, replace(trim($row[0]), /\\s/, "_"), $row[1]),json_set($acc, replace(trim($row[0]), /\\s/, "_"), json_array(json_extract($acc, replace(trim($row[0]), /\\s/,"_")), $row[1]))))\n| flatten tmp_EventData_Xml\n| fields - tmp_EventData_Xml\n           | eval tmp_RenderingInfo_Xml = replace(RenderingInfo_Xml, /(?ms)<(\\w*)>([^<]*)<\\/\\1>/, "##SEP##\\\\1##VAL_SEP##\\\\2##SEP##")\n| eval tmp_RenderingInfo_Xml = filter(split(tmp_RenderingInfo_Xml, "##SEP##"), $row -> match($row, /.*##VAL_SEP##.*/ ))\n| eval tmp_RenderingInfo_Xml = map(tmp_RenderingInfo_Xml, $row -> split($row, "##VAL_SEP##" ))\n| eval tmp_RenderingInfo_Xml = reduce(tmp_RenderingInfo_Xml, json_object(), ($acc, $row)-> if(isnull(json_extract($acc, replace(trim($row[0]), /\\s/, "_"))),json_set($acc, replace(trim($row[0]), /\\s/, "_"), $row[1]),json_set($acc, replace(trim($row[0]), /\\s/, "_"), json_array(json_extract($acc, replace(trim($row[0]), /\\s/,"_")), $row[1]))))\n| flatten tmp_RenderingInfo_Xml\n| fields - tmp_RenderingInfo_Xml\n           | rex field=EventRecordID /(?P<RecordNumber>.+)/\n           | rex field=_raw /<EventID.*?>(?P<EventCode>.+?)<\\/EventID>.*/\n           | rex field=EventID /(?P<EventCode>.+)/\n           | rex field=SubStatus /(?P<Sub_Status>.+)/\n           | rex field=Image_File_Name /^(?P<file_path>.*[\\\\\\/]+)*(?P<file_name>.*)$/\n\n           // field alias based extractions\n\n           | eval category = TaskCategory\n           | eval dvc_nt_host = host\n           | eval dvc = Computer\n           | eval event_id = RecordNumber\n           | eval severity_id = Level\n           | eval id = RecordNumber\n           | eval user_group_id = Primary_Group_ID\n           | eval service = ServiceName\n           | eval service_name = ServiceName\n           | eval service_id = ServiceSid\n           | eval parent_process = coalesce(parent_process, ParentProcessName)\n           | eval user_id = UserID\n           | eval SourceName = ProviderName\n\n           // eval based extractions\n\n           | eval signature_id = if(match(Name,"Microsoft-Windows-WindowsUpdateClient"),signature_id,EventCode)\n           | eval process_name = if(EventCode==4688, NewProcessName, ProcessName)\n           | eval vendor_product = "Microsoft Windows"\n\n           // lookup extractions\n\n           | lookup xmlwindows_task_category_lookup Task OUTPUTNEW TaskCategory\n           | eval TaskCategory = if(TaskCategory == "<nil>", null, TaskCategory)\n           | lookup windows_signature_lookup signature_id OUTPUTNEW CategoryString, action, result\n           | eval CategoryString = if(CategoryString == "<nil>", null, CategoryString)\n           | eval action = if(action == "<nil>", null, action)\n           | eval result = if(result == "<nil>", null, result)\n           | lookup xmlwindows_severity_lookup Level OUTPUTNEW severity\n           | lookup windows_signature_lookup signature_id OUTPUTNEW signature, signature AS name, signature AS subject\n           | eval signature = if(signature == "<nil>", null, signature)\n           | eval name = if(name == "<nil>", null, name)\n           | eval subject = if(subject == "<nil>", null, subject)\n\n           // default_lookup_extractions\n\n\n           // scripted_lookups\n\n}\n\n\n\n/**\n * This function trims any leading or trailing whitespaces from the field\'s value.\n */\nfunction trim_fields($source: dataset):dataset {\n    return | from $source\n           | eval System_Props_Xml = trim(System_Props_Xml)\n           | eval UserData_Xml = trim(UserData_Xml)\n           | eval EventData_Xml = trim(EventData_Xml)\n           | eval FailureReason = trim(FailureReason)\n           | eval AccessList = trim(AccessList)\n           | eval Properties = trim(Properties)\n           | eval AccessReason = trim(AccessReason)\n}\n\n/*\nPipeline.\n*/\n$pipeline = | from $source\n\n            | branch\n\n            [ where source="XmlWinEventLog:System" | XmlWinEventLog | XmlWinEventLog_System | trim_fields | into $destination],\n            [ where source="XmlWinEventLog:Security" | XmlWinEventLog | XmlWinEventLog_Security | trim_fields | into $destination],\n            [ where source="XmlWinEventLog:Application" | XmlWinEventLog | XmlWinEventLog_Application | trim_fields | into $destination],\n            [ where source="XmlWinEventLog:Microsoft-Windows-PowerShell/Operational" | XmlWinEventLog | XmlWinEventLog_Microsoft_Windows_PowerShell_Operational | trim_fields | into $destination],\n            [ where source!="XmlWinEventLog:System" AND source!="XmlWinEventLog:Security" AND source!="XmlWinEventLog:Application" AND source!="XmlWinEventLog:Microsoft-Windows-PowerShell/Operational" AND source!="XmlWinEventLog" | XmlWinEventLog | trim_fields | into $destination]\n'},2132:e=>{"use strict";e.exports='import apply_linebreak from /splunk/ingest/commands/schematize\n\n\n/** @description This is sourcetype configuration for auditd from TA:Splunk_TA_nix @readonly */\n@partition_for(function_ref: linebreak, conditions: [\\"auditd\\"])\nfunction bds_lb_for_func_auditd($source: dataset): dataset {\n return | from $source | apply_linebreak line_breaker=\\"([\\\\r\\\\n]+)\\" should_linemerge=false\n}\nexport bds_lb_for_func_auditd\n'},21